function hasClass(node, cls) {
  const list = String(node.className || '').split(/\s+/).filter(Boolean);
  return list.includes(cls);
}

function matchesSimple(node, selector) {
  if (!node || typeof selector !== 'string') return false;
  const s = selector.trim();
  if (!s) return false;

  if (s.startsWith('#')) {
    const id = s.slice(1);
    if (!id) return false;
    return String(node.id || '') === id;
  }

  if (s.startsWith('.')) {
    const cls = s.slice(1);
    if (!cls) return false;
    return hasClass(node, cls);
  }

  const parts = s.split('.');
  const tag = parts[0];
  const cls = parts[1];
  if (!tag) return false;

  if (String(node.tagName || '').toLowerCase() !== tag.toLowerCase()) return false;
  if (cls) return hasClass(node, cls);
  return true;
}

export default function closestSimple(node, selector) {
  if (!node || typeof selector !== 'string' || selector.trim() === '') return null;

  let cur = node;
  while (cur) {
    if (matchesSimple(cur, selector)) return cur;
    cur = cur.parentNode || null;
  }
  return null;
}
